INSERT INTO public.exercises (external_id,name,muscle_group,secondary_muscles,equipment,category,instructions,description,image_url,source,is_public) VALUES ('Smith_Machine_Calf_Raise','Smith Machine Calf Raise','pantorrillas',ARRAY[]::text[],'máquina','strength',ARRAY['Place a block or weight plate below the bar on the Smith machine. Set the bar to a position that best matches your height. Once the correct height is chosen and the bar is loaded, step onto the plates with the balls of your feet and place the bar on the back of your shoulders.','Take the bar with both hands facing forward. Rotate the bar to unrack it. This will be your starting position.','Raise your heels as high as possible by pushing off of the balls of your feet, flexing your calf at the top of the contraction. Your knees should remain extended. Hold the contracted position for a second before you start to go back down.','Return slowly to the starting position as you breathe in while lowering your heels.','Repeat for the recommended amount of repetitions.'],'Place a block or weight plate below the bar on the Smith machine. Set the bar to a position that best matches your height. Once the correct height is chosen and the bar is loaded, step onto the plates with the balls of your feet and place the bar on the back of your shoulders. Take the bar with both hands facing forward. Rotate the bar to unrack it. This will be your starting position. Raise your heels as high as possible by pushing off of the balls of your feet, flexing your calf at the top of the contraction. Your knees should remain extended. Hold the contracted position for a second before you start to go back down. Return slowly to the starting position as you breathe in while lowering your heels. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Calf_Raise/0.jpg','exercisedb',true),('Smith_Machine_Close-Grip_Bench_Press','Smith Machine Close-Grip Bench Press','tríceps',ARRAY['pecho','hombros'],'máquina','strength',ARRAY['Place a flat bench underneath the smith machine. Place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the flat bench. Using a close and pronated grip (palms facing forward) that is around shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that as opposed to a regular bench press, you keep the elbows close to the torso at all times in order to maximize triceps involvement.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your triceps muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, lock the bar back in the rack.'],'Place a flat bench underneath the smith machine. Place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the flat bench. Using a close and pronated grip (palms facing forward) that is around shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position. As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that as opposed to a regular bench press, you keep the elbows close to the torso at all times in order to maximize triceps involvement. After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your triceps muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up. Repeat the movement for the prescribed amount of repetitions. When you are done, lock the bar back in the rack.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Close-Grip_Bench_Press/0.jpg','exercisedb',true),('Smith_Machine_Decline_Press','Smith Machine Decline Press','pecho',ARRAY['hombros','tríceps'],'máquina','strength',ARRAY['Position a decline bench in the rack so that the bar will be above your chest. Load an appropriate weight and take your place on the bench.','Rotate the bar to unhook it from the rack and fully extend your arms. Your back should be slightly arched and your shoulder blades retracted. This will be your starting position.','Begin the movement by flexing your arms, lowering the bar to your chest.','Pause briefly, and then extend your arms to push the weight back to the starting position.','After completing the desired number of repetitions, rotate the bar to rack the weight.'],'Position a decline bench in the rack so that the bar will be above your chest. Load an appropriate weight and take your place on the bench. Rotate the bar to unhook it from the rack and fully extend your arms. Your back should be slightly arched and your shoulder blades retracted. This will be your starting position. Begin the movement by flexing your arms, lowering the bar to your chest. Pause briefly, and then extend your arms to push the weight back to the starting position. After completing the desired number of repetitions, rotate the bar to rack the weight.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Decline_Press/0.jpg','exercisedb',true),('Smith_Machine_Hang_Power_Clean','Smith Machine Hang Power Clean','isquiotibiales',ARRAY['glúteos','espalda baja','cuádriceps','hombros','trapecios'],'máquina','strength',ARRAY['Position the bar at knee height and load it to an appropriate weight.','Take a pronated grip on the bar outside of shoulder width and unhook the bar from the machine. Your arms should be fully extended with your head and chest up. Your elbows should be pointed out with your shoulders back and down. Your hips should be back, loading the tension into the hamstrings. This will be your starting position.','Initate the movement by forcefully extending the hips and knees, accelerating into the bar. Ensure that you keep your arms straight during this part of the motion.','Upon full extension, rebend the hips and knees to lower your receiving position.','Allow the arms to flex at this point, rotating the elbows around the bar to receive it on your shoulders.','Extend through the hips and knees to come to a standing position with the bar racked on your shoulders to complete the movement.'],'Position the bar at knee height and load it to an appropriate weight. Take a pronated grip on the bar outside of shoulder width and unhook the bar from the machine. Your arms should be fully extended with your head and chest up. Your elbows should be pointed out with your shoulders back and down. Your hips should be back, loading the tension into the hamstrings. This will be your starting position. Initate the movement by forcefully extending the hips and knees, accelerating into the bar. Ensure that you keep your arms straight during this part of the motion. Upon full extension, rebend the hips and knees to lower your receiving position. Allow the arms to flex at this point, rotating the elbows around the bar to receive it on your shoulders. Extend through the hips and knees to come to a standing position with the bar racked on your shoulders to complete the movement.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Hang_Power_Clean/0.jpg','exercisedb',true),('Smith_Machine_Hip_Raise','Smith Machine Hip Raise','abdominales',ARRAY[]::text[],'máquina','strength',ARRAY['Position a bench in the rack and load the bar to an appropriate weight. Lie down on the bench, placing the bottom of your feet against the bar. Unlock the bar and extend your legs. You may need to use your hands to assist you. For added stability grasp the sides of the Smith Machine. This will be your starting position.','Initiate the movement by rotating your pelvis, flexing your spine to raise your hips off of the bench. Maintain a slight bend in the knees throughout the motion.','After a brief pause, return the hips to the bench.','Repeat for the desired number of repetitions.'],'Position a bench in the rack and load the bar to an appropriate weight. Lie down on the bench, placing the bottom of your feet against the bar. Unlock the bar and extend your legs. You may need to use your hands to assist you. For added stability grasp the sides of the Smith Machine. This will be your starting position. Initiate the movement by rotating your pelvis, flexing your spine to raise your hips off of the bench. Maintain a slight bend in the knees throughout the motion. After a brief pause, return the hips to the bench. Repeat for the desired number of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Hip_Raise/0.jpg','exercisedb',true),('Smith_Machine_Incline_Bench_Press','Smith Machine Incline Bench Press','pecho',ARRAY['hombros','tríceps'],'máquina','strength',ARRAY['Place an incline bench underneath the smith machine. Place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the incline bench and make sure your upper chest is aligned with the barbell. Using a pronated grip (palms facing forward) that is wider than shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on your upper chest.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.'],'Place an incline bench underneath the smith machine. Place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Once the weight you need is selected, lie down on the incline bench and make sure your upper chest is aligned with the barbell. Using a pronated grip (palms facing forward) that is wider than shoulder width, unlock the bar from the rack and hold it straight over you with your arms locked. This will be your starting position. As you breathe in, come down slowly until you feel the bar on your upper chest. After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up. Repeat the movement for the prescribed amount of repetitions. When you are done, place the bar back in the rack.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Incline_Bench_Press/0.jpg','exercisedb',true),('Smith_Machine_Leg_Press','Smith Machine Leg Press','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales'],'máquina','strength',ARRAY['Position a Smith machine bar a couple feet off of the ground. Ensure that it is resting on the safeties. After loading the bar to an appropriate weight, lie underneath the bar. Place the middle of your feet on the bar, tucking your knees to your chest. This will be your starting position.','Begin the movement by driving through your feet to move the bar upward, extending the hips and knees. Do not lock out your knees.','At the top of the motion, pause briefly before returning to the starting position.'],'Position a Smith machine bar a couple feet off of the ground. Ensure that it is resting on the safeties. After loading the bar to an appropriate weight, lie underneath the bar. Place the middle of your feet on the bar, tucking your knees to your chest. This will be your starting position. Begin the movement by driving through your feet to move the bar upward, extending the hips and knees. Do not lock out your knees. At the top of the motion, pause briefly before returning to the starting position.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Leg_Press/0.jpg','exercisedb',true),('Smith_Machine_One-Arm_Upright_Row','Smith Machine One-Arm Upright Row','hombros',ARRAY['bíceps','trapecios'],'máquina','strength',ARRAY['With the bar at thigh level, load an appropriate weight.','Take a wide grip on the bar and unhook the weight, removing your off hand from the bar. Your arm should be extended as you stand up straight with your head and chest up. This will be your starting position.','Begin the movement by flexing the elbow, raising the upper arm with the elbow pointed out. Continue until your upper arm is parallel to the floor.','After a brief pause, return the weight to the starting position.','Repeat for the desired number of repetitions before engaging the hooks to rack the weight.'],'With the bar at thigh level, load an appropriate weight. Take a wide grip on the bar and unhook the weight, removing your off hand from the bar. Your arm should be extended as you stand up straight with your head and chest up. This will be your starting position. Begin the movement by flexing the elbow, raising the upper arm with the elbow pointed out. Continue until your upper arm is parallel to the floor. After a brief pause, return the weight to the starting position. Repeat for the desired number of repetitions before engaging the hooks to rack the weight.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_One-Arm_Upright_Row/0.jpg','exercisedb',true),('Smith_Machine_Overhead_Shoulder_Press','Smith Machine Overhead Shoulder Press','hombros',ARRAY['tríceps'],'máquina','strength',ARRAY['To begin, place a flat bench (or preferably one with back support) underneath a smith machine. Position the barbell at a height so that when seated on the flat bench, the arms must be almost fully extended to reach the barbell.','Once you have the correct height, sit slightly in behind the barbell so that there is an imaginary straight line from the tip of your nose to the barbell. Your feet should be stationary. Grab the barbell with the palms facing forward, unlock it and lift it up so that your arms are fully extended. This is the starting position.','Slowly begin to lower the barbell until it is level with your chin while inhaling.','Then lift the barbell back to the starting position using your shoulders while exhaling.','Repeat for the recommended amount of repetitions.'],'To begin, place a flat bench (or preferably one with back support) underneath a smith machine. Position the barbell at a height so that when seated on the flat bench, the arms must be almost fully extended to reach the barbell. Once you have the correct height, sit slightly in behind the barbell so that there is an imaginary straight line from the tip of your nose to the barbell. Your feet should be stationary. Grab the barbell with the palms facing forward, unlock it and lift it up so that your arms are fully extended. This is the starting position. Slowly begin to lower the barbell until it is level with your chin while inhaling. Then lift the barbell back to the starting position using your shoulders while exhaling. Repeat for the recommended amount of repetitions.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Overhead_Shoulder_Press/0.jpg','exercisedb',true),('Smith_Machine_Pistol_Squat','Smith Machine Pistol Squat','cuádriceps',ARRAY['pantorrillas','glúteos','isquiotibiales'],'máquina','strength',ARRAY['To begin, first set the bar to a position that best matches your height. Step under it and position the bar across the back of your shoulders.','Take the bar with your hands facing forward, unlock it and lift it off the rack by extending your legs. 3','Move one foot forward about 12 inches in front of the bar. Extend the other leg out in front of you, holding it off the ground. Look forward at all times and maintain a neutral or slightly arched spine. This will be your starting position.','Maintaining good posture, lower yourself by flexing the knee and hip, going down as far as flexibility allows.','Pause briefly at the bottom and then return to the starting position by driving through the heel of your foot, extending the knee and hip.'],'To begin, first set the bar to a position that best matches your height. Step under it and position the bar across the back of your shoulders. Take the bar with your hands facing forward, unlock it and lift it off the rack by extending your legs. 3 Move one foot forward about 12 inches in front of the bar. Extend the other leg out in front of you, holding it off the ground. Look forward at all times and maintain a neutral or slightly arched spine. This will be your starting position. Maintaining good posture, lower yourself by flexing the knee and hip, going down as far as flexibility allows. Pause briefly at the bottom and then return to the starting position by driving through the heel of your foot, extending the knee and hip.','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Smith_Machine_Pistol_Squat/0.jpg','exercisedb',true);